query.sparql:
SELECT DISTINCT ?animal ?animalLabel WHERE {
  ?operation wdt:P710 wd:Q625657. # Operations involving the Australian Defence Force
  ?operation ?property ?animal. # Any property linking the operation to an animal
  ?animal wdt:P31 wd:Q729. # Ensuring the entity is an animal
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
LIMIT 50

SELECT ?answer WHERE {
  wd:Q4205826 wdt:P451 ?answer .
  wd:Q4463198 wdt:P451 ?answer .
}

SELECT ?answer WHERE {
  wd:Q860580 wdt:P112 ?answer. # Tencent's founders
  ?answer wdt:P463 wd:Q19211. # Members of National People's Congress
}

SELECT ?answer WHERE {
  VALUES ?work { wd:Q483557 wd:Q696071 wd:Q18225473 }
  ?work ?p ?statement.
  ?statement rdfs:label ?label.
  FILTER(CONTAINS(LCASE(?label), "middle school student"))
  BIND(?work AS ?answer)
}
